import sys
import re

def pattern_to_regex(pattern):
    # Escape '.' to '\.'
    # Replace '*' with '.*'
    regex = ''
    for ch in pattern:
        if ch == '*':
            regex += '.*'
        elif ch == '.':
            regex += r'\.'
        else:
            regex += ch
    return '^' + regex + '$'

