def number_to_words(n):
    ones = ["one","two","three","four","five","six","seven","eight","nine"]
    teens = ["eleven","twelve","thirteen","fourteen","fifteen","sixteen","seventeen","eighteen","nineteen"]
    tens = ["ten","twenty","thirty","forty","fifty","sixty","seventy","eighty","ninety"]
    hundreds = ["onehundred","twohundred","threehundred","fourhundred","fivehundred","sixhundred","sevenhundred","eighthundred","ninehundred"]

    if n == 0:
        return ""
    if n <= 9:
        return ones[n-1]
    if 11 <= n <= 19:
        return teens[n-11]
    if n == 10:
        return tens[0]
    if 20 <= n <= 99:
        t = n // 10
        o = n % 10
        return tens[t-1] + (ones[o-1] if o != 0 else "")
    if 100 <= n <= 999:
        h = n // 100
        rem = n % 100
        return hundreds[h-1] + (number_to_words(rem) if rem != 0 else "")
    return ""

