def cross(ax, ay, bx, by):
    return ax * by - ay * bx

def area2(x1, y1, x2, y2, x3, y3):
    return abs(cross(x2 - x1, y2 - y1, x3 - x1, y3 - y1))

def normalize_polygon(poly):
    # poly is list of (x,y) in CCW order
    # normalize by rotating so that minimal vertex is first
    n = len(poly)
    # find minimal vertex lex order
    min_idx = 0
    for i in range(1, n):
        if poly[i] < poly[min_idx]:
            min_idx = i
    # rotate
    poly = poly[min_idx:] + poly[:min_idx]
    # also consider reversed polygon and pick lex smaller
    rev = poly[::-1]
    min_idx_rev = 0
    for i in range(1, n):
        if rev[i] < rev[min_idx_rev]:
            min_idx_rev = i
    rev = rev[min_idx_rev:] + rev[:min_idx_rev]
    if rev < poly:
        poly = rev
    return tuple(poly)

def polygon_area(poly):
    # poly is list of (x,y) in CCW order
    area = 0
    n = len(poly)
    for i in range(n):
        x1, y1 = poly[i]
        x2, y2 = poly[(i+1)%n]
        area += x1*y2 - y1*x2
    return abs(area)

def polygon_edges(poly):
    n = len(poly)
    edges = []
    for i in range(n):
        x1, y1 = poly[i]
        x2, y2 = poly[(i+1)%n]
        edges.append((x1, y1, x2, y2))
    return edges

def point_eq(a, b):
    return a[0] == b[0] and a[1] == b[1]

def read_triangles(num):
    tris = []
    for _ in range(num):
        x1,y1,x2,y2,x3,y3 = map(int, input().split())
        # Check degenerate
        if area2(x1,y1,x2,y2,x3,y3) == 0:
            continue
        # Store triangle as sorted tuple of points (to avoid orientation issues)
        pts = [(x1,y1),(x2,y2),(x3,y3)]
        pts.sort()
        tris.append(tuple(pts))
    return tris

def build_adjacency(tris):
    # Build adjacency graph of triangles by shared edges
    # Map edges to triangle indices
    edge_map = defaultdict(list)
    for i, tri in enumerate(tris):
        pts = tri
        edges = []
        for j in range(3):
            a = pts[j]
            b = pts[(j+1)%3]
            if a < b:
                edge = (a,b)
            else:
                edge = (b,a)
            edges.append(edge)
            edge_map[edge].append(i)
    adj = [[] for _ in range(len(tris))]
    for edge, lst in edge_map.items():
        if len(lst) == 2:
            a,b = lst
            adj[a].append(b)
            adj[b].append(a)
    return adj

def merge_component(tris, comp):
    # Merge triangles in comp into polygon
    # The union polygon boundary edges are those edges that appear only once in the component
    edge_count = defaultdict(int)
    for i in comp:
        tri = tris[i]
        for j in range(3):
            a = tri[j]
            b = tri[(j+1)%3]
            if a < b:
                edge = (a,b)
            else:
                edge = (b,a)
            edge_count[edge] += 1
    boundary_edges = [e for e,cnt in edge_count.items() if cnt == 1]
    if not boundary_edges:
        # no boundary edges means no polygon (empty)
        return ()
    # Build polygon from boundary edges
    # Each edge is (p1,p2), we want to chain them in order
    # Build adjacency for boundary edges
    adj = defaultdict(list)
    for a,b in boundary_edges:
        adj[a].append(b)
        adj[b].append(a)
    # Find start vertex: vertex with degree 1 (start of polygon chain)
    start = None
    for v, nbrs in adj.items():
        if len(nbrs) == 1:
            start = v
            break
    if start is None:
        # polygon is closed loop, pick minimal vertex as start
        start = min(adj.keys())
    # Walk polygon boundary
    polygon = []
    visited_edges = set()
    current = start
    prev = None
    while True:
        polygon.append(current)
        nbrs = adj[current]
        next_vertex = None
        for nbr in nbrs:
            e = (current, nbr) if current < nbr else (nbr, current)
            if e not in visited_edges:
                next_vertex = nbr
                visited_edges.add(e)
                break
        if next_vertex is None:
            break
        prev = current
        current = next_vertex
        if current == start:
            break
    # polygon is list of points in order
    # Ensure polygon is CCW
    # Compute signed area
    area = 0
    n = len(polygon)
    for i in range(n):
        x1,y1 = polygon[i]
        x2,y2 = polygon[(i+1)%n]
        area += x1*y2 - y1*x2
    if area < 0:
        polygon.reverse()
    return normalize_polygon(polygon)

def get_polygons(tris):
    if not tris:
        return []
    adj = build_adjacency(tris)
    n = len(tris)
    visited = [False]*n
    polygons = []
    for i in range(n):
        if not visited[i]:
            # BFS to get component
            q = deque([i])
            comp = []
            visited[i] = True
            while q:
                u = q.popleft()
                comp.append(u)
                for w in adj[u]:
                    if not visited[w]:
                        visited[w] = True
                        q.append(w)
            poly = merge_component(tris, comp)
            if poly:
                polygons.append(poly)
    polygons.sort()
    return polygons

